CREATE OR REPLACE FUNCTION get_conversations_by_status() RETURNS TABLE(status TEXT, count BIGINT) AS \$\$ SELECT status, COUNT(*) FROM conversations GROUP BY status; \$\$ LANGUAGE SQL SECURITY DEFINER; CREATE OR REPLACE FUNCTION get_tenant_growth(weeks INT DEFAULT 8) RETURNS TABLE(week TIMESTAMP, count BIGINT) AS \$\$ SELECT DATE_TRUNC('week', created_at) as week, COUNT(*) FROM tenants WHERE created_at > NOW() - (weeks || ' weeks')::INTERVAL GROUP BY week ORDER BY week; \$\$ LANGUAGE SQL SECURITY DEFINER; CREATE OR REPLACE FUNCTION get_tenant_messages_by_day(p_tenant_id UUID, days INT DEFAULT 30) RETURNS TABLE(day TIMESTAMP, count BIGINT) AS \$\$ SELECT DATE_TRUNC('day', created_at) as day, COUNT(*) FROM messages WHERE tenant_id = p_tenant_id AND created_at > NOW() - (days || ' days')::INTERVAL GROUP BY day ORDER BY day; \$\$ LANGUAGE SQL SECURITY DEFINER;
